from flask import Flask, jsonify
from pymemcache.client import base
import time

app = Flask(__name__)
cache = base.Client(('localhost', 11211))

# Simulated database query function
def query_database(query):
    # Simulate a database query with a delay
    time.sleep(2)
    return {"data": f"Results for {query}"}

@app.route('/data/<query>', methods=['GET'])
def get_data(query):
    # Check cache first
    cached_result = cache.get(query)
    if cached_result:
        return jsonify({"source": "cache", "data": cached_result.decode('utf-8')})

    # If not in cache, query the database
    result = query_database(query)
    
    # Store result in cache with a TTL of 60 seconds
    cache.set(query, jsonify(result).data, expire=60)
    
    return jsonify({"source": "database", "data": result})

